{{defn|no=1 |defn=
Beginning of first definition of term 2
{{quote|1=Block quotation in first definition of term 2.}}
Conclusion of first definition of term 2.
}}
{{defn|no=2 |defn=Second definition of term 2.}}

{{glossary end}}
}} }}

